mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, a.* FROM ( SELECT r.REQ_SEQ, r.REQ_DATE, r.USERS_ID, u.NAME, r.REASON, r.STATUS, s.SUPPLY_NAME, i.ITEM_SEQ, i.SUPPLY_SEQ, i.EA, i.USE_TYPE FROM SUPPLY_REQUEST r JOIN SUPPLY_REQUEST_ITEMS i ON r.REQ_SEQ = i.REQ_SEQ JOIN SUPPLIES s ON i.SUPPLY_SEQ = s.SUPPLY_SEQ LEFT JOIN USERS u ON r.USERS_ID = u.ID
AND (s.SUPPLY_NAME LIKE '%' || #{keyword} || '%' OR u.NAME LIKE '%' || #{keyword} || '%')
AND r.STATUS = #{status}
ORDER BY r.REQ_DATE DESC, r.REQ_SEQ DESC ) a ) WHERE rn BETWEEN #{start} AND #{end}

SELECT COUNT(DISTINCT r.REQ_SEQ) FROM SUPPLY_REQUEST r JOIN SUPPLY_REQUEST_ITEMS i ON r.REQ_SEQ = i.REQ_SEQ JOIN SUPPLIES s ON i.SUPPLY_SEQ = s.SUPPLY_SEQ LEFT JOIN USERS u ON r.USERS_ID = u.ID
AND (s.SUPPLY_NAME LIKE '%' || #{keyword} || '%' OR u.NAME LIKE '%' || #{keyword} || '%')
AND r.STATUS = #{status}

mapper.update:
UPDATE SUPPLY_REQUEST
SET STATUS = #{status}
WHERE REQ_SEQ = #{req_seq}

UPDATE SUPPLIES
SET STOCK_QTY = STOCK_QTY - #{ea}
WHERE SUPPLY_SEQ = #{supply_seq}
AND STOCK_QTY >= #{ea}
